              <ShieldCheck size={48} className="text-gray-500 group-hover:text-neon transition-colors" />
              <span className="text-gray-500 text-sm tracking-widest group-hover:text-white">ZERO DATA LEAK</span>
            </div>
            <div className="col-span-2 border border-white/5 p-6 flex items-center justify-between hover:border-neon/50 transition-colors group relative overflow-hidden">
               <div className="z-10 flex items-center gap-4">
                 <Cpu size={48} className="text-gray-500 group-hover:text-neon transition-colors" />
                 <div className="flex flex-col">
                   <span className="text-xl font-display font-bold text-white">NPU OPTIMIZED</span>
                   <span className="text-xs text-gray-500 font-mono">Edge Computing Architecture</span>
                 </div>
               </div>
               <div className="absolute right-0 bottom-0 p-4 opacity-20">
                 <div className="flex gap-1 items-end h-12">
