import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { analyzeProjectFeasibility } from '../services/geminiService';
import { AiResponse } from '../types';
import { Brain, Terminal, Loader2, ArrowRight } from 'lucide-react';

const Lab: React.FC = () => {
  const [idea, setIdea] = useState('');
  const [analyzing, setAnalyzing] = useState(false);
  const [result, setResult] = useState<AiResponse | null>(null);

  const handleAnalyze = async () => {
    if (!idea.trim()) return;
    setAnalyzing(true);
    setResult(null);
    try {
      const data = await analyzeProjectFeasibility(idea);
      setResult(data);
    } catch (e) {
      console.error(e);
    } finally {
      setAnalyzing(false);
    }
  };

  return (
    <section id="lab" className="py-24 px-6 md:px-12 bg-obsidian-light border-y border-white/5 relative overflow-hidden">
      {/* Background Grid */}
      <div className="absolute inset-0 bg-[linear-gradient(to_right,#80808012_1px,transparent_1px),linear-gradient(to_bottom,#80808012_1px,transparent_1px)] bg-[size:24px_24px]"></div>

      <div className="max-w-6xl mx-auto relative z-10 grid grid-cols-1 lg:grid-cols-2 gap-16">
        <div>
          <h2 className="text-neon text-sm font-mono tracking-[0.2em] mb-4">/// ARCHITECTURE LAB</h2>
          <h3 className="text-4xl md:text-5xl font-display font-bold text-white mb-6">
            TEST YOUR <br/> CONCEPT
          </h3>
          <p className="text-text-secondary mb-8 font-light">
            Use our proprietary analysis engine (powered by Gemini) to determine if your app idea can be built using offline-first AI architecture.
          </p>

          <div className="bg-black/50 border border-white/10 p-1 backdrop-blur-md">
            <textarea 
              value={idea}
              onChange={(e) => setIdea(e.target.value)}
              placeholder="Describe your app functionality... e.g., 'An app that identifies rare plants from photos and gives care tips without internet.'"
              className="w-full h-40 bg-transparent text-white p-4 font-mono text-sm focus:outline-none resize-none placeholder-gray-700"
            />
            <div className="flex justify-between items-center p-2 bg-white/5 border-t border-white/10">
              <span className="text-xs text-gray-500 font-mono uppercase">
                {idea.length} chars
              </span>
              <button 
                onClick={handleAnalyze}
                disabled={analyzing || !idea}
                className="flex items-center gap-2 px-6 py-2 bg-neon text-black font-display font-bold uppercase hover:bg-white transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
              >
                {analyzing ? <Loader2 className="animate-spin" size={16} /> : <Terminal size={16} />}
                {analyzing ? 'Processing...' : 'Run Diagnostics'}
              </button>
            </div>
          </div>
        </div>

        <div className="relative">
          <AnimatePresence mode="wait">
            {!result && !analyzing && (
              <motion.div 
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                exit={{ opacity: 0 }}
                className="h-full flex flex-col justify-center items-center border border-dashed border-white/10 rounded-lg p-12 text-center"
              >
                <Brain size={64} className="text-white/20 mb-4" />
                <p className="text-white/30 font-mono text-sm">WAITING FOR INPUT STREAM...</p>
              </motion.div>
            )}

            {analyzing && (
               <motion.div 
               initial={{ opacity: 0 }}
               animate={{ opacity: 1 }}
               exit={{ opacity: 0 }}
               className="h-full flex flex-col justify-center items-center border border-neon/30 bg-neon/5 rounded-lg p-12 text-center"
             >
               <div className="w-16 h-16 border-4 border-neon border-t-transparent rounded-full animate-spin mb-6"></div>
               <p className="text-neon font-mono text-sm animate-pulse">ESTABLISHING NEURAL LINK...</p>
               <div className="mt-4 w-full max-w-xs h-1 bg-black/50 overflow-hidden">
                 <motion.div 
                    className="h-full bg-neon"
                    initial={{ width: "0%" }}
                    animate={{ width: "100%" }}
                    transition={{ duration: 2 }}
                 />
               </div>
             </motion.div>
            )}

            {result && (
              <motion.div
                initial={{ opacity: 0, x: 20 }}
                animate={{ opacity: 1, x: 0 }}
                className="h-full border border-white/20 bg-black/80 backdrop-blur-xl p-8 flex flex-col relative"
              >
                 <div className="absolute top-0 right-0 p-2">
                    <div className="w-2 h-2 rounded-full bg-neon animate-pulse"></div>
                 </div>

                 <div className="flex justify-between items-end mb-8 border-b border-white/10 pb-4">
                   <div>
                     <span className="text-gray-500 font-mono text-xs block mb-1">FEASIBILITY SCORE</span>
                     <span className="text-5xl font-display font-bold text-white">{result.feasibilityScore}/100</span>
                   </div>
                   <div className="text-right">
                      <span className="text-gray-500 font-mono text-xs block mb-1">RECOMMENDATION</span>
                      <span className={`font-display font-bold text-lg ${result.feasibilityScore > 70 ? 'text-neon' : 'text-alert'}`}>
                        {result.feasibilityScore > 70 ? 'APPROVED' : 'CAUTION'}
                      </span>
                   </div>
                 </div>

                 <div className="mb-6">
                   <h4 className="text-white font-bold font-display uppercase mb-2">Analysis Log</h4>
                   <p className="text-gray-400 text-sm leading-relaxed font-mono">
                     {result.analysis}
                   </p>
                 </div>

                 <div className="mt-auto bg-white/5 p-4 border-l-2 border-neon">
                   <h4 className="text-neon font-bold font-display uppercase mb-1">Next Step</h4>
                   <p className="text-gray-300 text-sm">{result.recommendation}</p>
                 </div>
              </motion.div>
            )}
          </AnimatePresence>
        </div>
      </div>
    </section>
  );
};

