  }, [location]);

  const handleNavClick = (sectionId: string) => {
    setIsOpen(false);
    if (location.pathname !== '/') {
      navigate('/');
      // Wait for navigation to complete then scroll
      setTimeout(() => {
        const element = document.getElementById(sectionId);
        if (element) element.scrollIntoView({ behavior: 'smooth' });
      }, 100);
    } else {
      const element = document.getElementById(sectionId);
      if (element) element.scrollIntoView({ behavior: 'smooth' });
    }
  };

  return (
    <>
      <nav className={`fixed top-0 left-0 w-full z-50 transition-all duration-300 ${scrolled ? 'bg-obsidian/80 backdrop-blur-md border-b border-white/5 py-4' : 'bg-transparent py-8'}`}>
        <div className="max-w-7xl mx-auto px-6 md:px-12 flex justify-between items-center">
          <Link to="/" className="text-2xl font-display font-bold tracking-tighter text-white flex items-center gap-2 z-50">
            <div className="w-3 h-3 bg-neon"></div>
            OBSIDIAN
          </Link>

          <div className="hidden md:flex gap-8 items-center">
             <Link 
              to="/" 
              className="text-sm font-mono text-gray-400 hover:text-neon tracking-widest uppercase transition-colors"
             >
               Home
             </Link>

             {/* Dropdown Trigger */}
             <div 
                className="relative group h-full flex items-center"
                onMouseEnter={() => setDropdownOpen(true)}
                onMouseLeave={() => setDropdownOpen(false)}
             >
                <button 
                  className="flex items-center gap-1 text-sm font-mono text-gray-400 hover:text-neon tracking-widest uppercase transition-colors py-2"
                >
                  Apps <ChevronDown size={14} className={`transition-transform duration-300 ${dropdownOpen ? 'rotate-180' : ''}`} />
                </button>

                <AnimatePresence>
                  {dropdownOpen && (
                    <motion.div
                      initial={{ opacity: 0, y: 10, scale: 0.95 }}
                      animate={{ opacity: 1, y: 0, scale: 1 }}
                      exit={{ opacity: 0, y: 10, scale: 0.95 }}
                      transition={{ duration: 0.2 }}
                      className="absolute top-full left-1/2 -translate-x-1/2 pt-4 w-64"
                    >
                      <div className="bg-obsidian border border-white/10 p-2 shadow-2xl shadow-neon/10 backdrop-blur-xl">
                        {products.map((p) => (
                          <Link 
                            key={p.id} 
                            to={`/apps/${p.id}`}
                            className="block p-3 hover:bg-white/5 group/item border-b border-transparent last:border-0 transition-colors"
                          >
                            <div className={`text-xs font-mono mb-1 ${p.primaryColor}`}>{p.shortName}</div>
                            <div className="text-white font-display font-bold text-sm group-hover/item:translate-x-1 transition-transform">{p.name}</div>
                          </Link>
                        ))}
                      </div>
                    </motion.div>
                  )}
                </AnimatePresence>
             </div>

             <button 
               onClick={() => handleNavClick('philosophy')}
               className="text-sm font-mono text-gray-400 hover:text-neon tracking-widest uppercase transition-colors"
             >
               Philosophy
             </button>

             <button 
               onClick={() => handleNavClick('technology')}
               className="text-sm font-mono text-gray-400 hover:text-neon tracking-widest uppercase transition-colors"
             >
               Tech
             </button>

            <Link 
               to="/apps/vault"
               className="text-sm font-mono bg-white text-black px-4 py-1 hover:bg-neon transition-colors font-bold uppercase tracking-wider"
            >
              Get Access
            </Link>
          </div>

          <button className="md:hidden text-white z-50" onClick={() => setIsOpen(!isOpen)}>
            {isOpen ? <X /> : <Menu />}
          </button>
        </div>
      </nav>

      <AnimatePresence>
        {isOpen && (
          <motion.div 
            initial={{ opacity: 0, x: '100%' }}
            animate={{ opacity: 1, x: 0 }}
            exit={{ opacity: 0, x: '100%' }}
            transition={{ type: 'tween', duration: 0.3 }}
            className="fixed inset-0 bg-obsidian z-[40] flex flex-col items-center justify-center gap-8 pt-20"
          >
             <Link to="/" onClick={() => setIsOpen(false)} className="text-3xl font-display font-bold text-white hover:text-neon tracking-wider uppercase">
                Home
             </Link>
             <div className="text-gray-500 font-mono text-sm uppercase tracking-widest mt-4">Applications</div>
             {products.map(p => (
               <Link 
                 key={p.id} 
                 to={`/apps/${p.id}`}
                 onClick={() => setIsOpen(false)}
                 className="text-2xl font-display font-bold text-white hover:text-neon tracking-wider uppercase"
               >
                 {p.shortName}
               </Link>
             ))}

             <button onClick={() => handleNavClick('philosophy')} className="text-xl font-mono text-gray-400 hover:text-neon tracking-widest uppercase">
               Philosophy
             </button>
             <button onClick={() => handleNavClick('technology')} className="text-xl font-mono text-gray-400 hover:text-neon tracking-widest uppercase">
               Technology
             </button>

            <div className="mt-8 text-gray-500 font-mono text-xs">
              SYSTEM STATUS: ONLINE
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </>
  );
};

