import React, { useEffect } from 'react';
import { useParams, Navigate, Link } from 'react-router-dom';
import { motion, useScroll, useTransform } from 'framer-motion';
import { blogPosts } from '../data/blog';
import { products } from '../data/products';
import { ArrowLeft, Clock, Calendar, Share2, Download, Terminal } from 'lucide-react';

const BlogPost: React.FC = () => {
  const { id } = useParams();
  const post = blogPosts.find(p => p.id === id);
  const { scrollYProgress } = useScroll();
  const scaleX = useTransform(scrollYProgress, [0, 1], [0, 1]);

  useEffect(() => {
     window.scrollTo(0, 0);
  }, [id]);

  if (!post) return <Navigate to="/blog" replace />;

  const renderBlock = (block: any, idx: number) => {
    switch (block.type) {
      case 'paragraph':
        return <p key={idx} className="mb-8 text-lg text-gray-300 font-light leading-relaxed">{block.content}</p>;
      case 'h2':
        return <h2 key={idx} className="text-3xl font-display font-bold text-white mt-12 mb-6">{block.content}</h2>;
      case 'quote':
        return (
          <blockquote key={idx} className="border-l-4 border-neon pl-6 my-12 italic text-2xl text-gray-400 font-display">
            "{block.content}"
          </blockquote>
        );
      case 'code':
        return (
          <div key={idx} className="bg-black border border-white/10 p-6 rounded my-8 font-mono text-sm text-green-400 overflow-x-auto">
            {block.content}
          </div>
        );
