const BlogPost: React.FC = () => {
  const { id } = useParams();
  const post = blogPosts.find(p => p.id === id);
  const { scrollYProgress } = useScroll();
  const progressScale = useTransform(scrollYProgress, [0, 1], [0, 1]);

  useEffect(() => {
     window.scrollTo(0, 0);
  }, [id]);

  if (!post) return <Navigate to="/blog" replace />;

  const renderBlock = (block: any, idx: number) => {
    switch (block.type) {
      case 'paragraph':
        return <p key={idx} className="mb-10 text-xl text-gray-300 font-light leading-[1.8]">{block.content}</p>;
      case 'h2':
        return (
          <h2 key={idx} className="text-4xl md:text-5xl font-display font-bold text-white mt-20 mb-10 leading-tight">
            {block.content}
          </h2>
        );
      case 'quote':
        return (
          <div key={idx} className="relative my-16 px-12 py-8 border-l-2 border-neon bg-white/[0.02]">
