             <blockquote className="text-3xl font-display font-bold text-gray-200 italic leading-snug">
               {block.content}
             </blockquote>
          </div>
        );
      case 'code':
        return (
          <div key={idx} className="bg-[#0c0c0c] border border-white/5 p-8 rounded-sm my-12 font-mono text-sm leading-relaxed text-gray-400 group relative">
